arguments.command:
$content = Get-Content "C:\Users\HAOLIN~1\AppData\Local\Temp\copilot-tool-output-1781752910714-voncm8.txt" -Raw
$warnings = [regex]::Matches($content, '(\S+\.tsp):(\d+):(\d+) - warning (\S+): (.+?)(?=\r?\n|$)')
$results = $warnings | ForEach-Object { [PSCustomObject]@{File=$_.Groups[1].Value; Line=[int]$_.Groups[2].Value; Col=[int]$_.Groups[3].Value; Code=$_.Groups[4].Value} }

# Clean file names (remove "compilation:" prefix if present)
$results = $results | ForEach-Object { $_.File = $_.File -replace '^compilation:', ''; $_ }

# Group by file then by line, collecting unique codes per line
$byFile = $results | Group-Object File
foreach ($fg in $byFile) {
    Write-Host "File: $($fg.Name)"
    $byLine = $fg.Group | Group-Object Line
    foreach ($lg in ($byLine | Sort-Object { [int]$_.Name })) {
        $codes = ($lg.Group | Select-Object -ExpandProperty Code -Unique) -join ", "
        Write-Host "  Line $($lg.Name): $codes"
    }
}

Set-Location "C:\Users\HAOLIN~1\AppData\Local\Temp\vally-eval-riZOOE"

# Parse all warnings
$compileOutput = Get-Content "C:\Users\HAOLIN~1\AppData\Local\Temp\copilot-tool-output-1781752910714-voncm8.txt" -Raw
$warningMatches = [regex]::Matches($compileOutput, '(\S+\.tsp):(\d+):(\d+) - warning (\S+):')

# Build a dictionary: file -> { line -> [codes] }
$fileWarnings = @{}
foreach ($m in $warningMatches) {
    $file = $m.Groups[1].Value -replace '^compilation:', ''
    $line = [int]$m.Groups[2].Value
    $code = $m.Groups[4].Value

    if (-not $fileWarnings.ContainsKey($file)) { $fileWarnings[$file] = @{} }
    if (-not $fileWarnings[$file].ContainsKey($line)) { $fileWarnings[$file][$line] = [System.Collections.Generic.HashSet[string]]::new() }
    [void]$fileWarnings[$file][$line].Add($code)
}

$justification = 'FIXME: Update justification, follow aka.ms/tsp/conversion-fix for details'

foreach ($file in $fileWarnings.Keys) {
    $lines = Get-Content $file
    $newLines = [System.Collections.Generic.List[string]]::new()

    for ($i = 0; $i -lt $lines.Count; $i++) {
        $lineNum = $i + 1  # 1-based
        $currentLine = $lines[$i]

        if ($fileWarnings[$file].ContainsKey($lineNum)) {
            # Determine indentation from the current line
            $indent = ""
            if ($currentLine -match '^(\s+)') { $indent = $Matches[1] }

            # Get codes for this line, check which are already suppressed on previous lines
            $codes = $fileWarnings[$file][$lineNum]
            foreach ($code in ($codes | Sort-Object)) {
                # Check if there's already a suppress for this code on the lines just before
                $alreadySuppressed = $false
                for ($j = $newLines.Count - 1; $j -ge [Math]::Max(0, $newLines.Count - 10); $j--) {
                    if ($newLines[$j] -match "^\s*$" -or $newLines[$j] -match '^\s*#suppress\s') {
                        if ($newLines[$j] -match "#suppress\s+`"$([regex]::Escape($code))`"") {
                            $alreadySuppressed = $true
                            break
                        }
                    } else {
                        break
                    }
                }
                if (-not $alreadySuppressed) {
                    $newLines.Add("${indent}#suppress `"${code}`" `"${justification}`"")
                }
            }
        }
        $newLines.Add($currentLine)
    }

    Set-Content -Path $file -Value ($newLines -join "`n") -NoNewline
    Write-Host "Updated $file : $($lines.Count) -> $($newLines.Count) lines"
}
